  // This checks if X is clamped within [Lo, Hi] range.
  {
    Value *X;
    const APInt *Lo, *Hi;
    // Match: icmp eq/ne X, smin(smax(X, Lo), Hi)
    auto tryFoldClampRange = [&](Value *CmpOp, Value *XVal, const APInt *LoVal,
                                  const APInt *HiVal) -> Instruction * {
      if (!LoVal->sle(*HiVal))
        return nullptr;
      Type *Ty = XVal->getType();
      // Range size is Hi - Lo + 1
      APInt RangeSize = *HiVal - *LoVal + 1;
      // We want (X - Lo) u< RangeSize
      // For smin/smax, we need signed comparison, but for the optimized
      // form we use unsigned.
      // If Lo is negative, subtracting it is equivalent to adding its absolute value.
      // Try to fold the constant into X if X is an add with a constant.
      Value *NewX;
      Constant *Offset = ConstantInt::get(Ty, -*LoVal);
      Value *A, *B;
      Constant *C;
      // Try to reassociate: if X = (A + C), then X - Lo = A + (C - Lo)
      // But we actually want X + (-Lo), so try to fold -Lo into existing constants
      if (match(XVal, m_Add(m_Value(A), m_ImmConstant(C)))) {
