        NewX = Builder.CreateAdd(A, NewC);
      } else if (match(XVal, m_Add(m_ImmConstant(C), m_Value(A)))) {
        // X = C + A, so X - Lo = C + A - Lo = A + (C - Lo)
        Constant *NewC = ConstantExpr::getAdd(C, Offset);
        NewX = Builder.CreateAdd(A, NewC);
      } else {
        // Default: just subtract Lo from X
        NewX = Builder.CreateAdd(XVal, Offset);
      }
      ICmpInst::Predicate NewPred =
          Pred == ICmpInst::ICMP_EQ ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE;
      return new ICmpInst(NewPred, NewX, ConstantInt::get(Ty, RangeSize));
    };

